package com.broadridge.ebcdic;public class InputCFG {	String fId;	String recID;	String recordType;	String fieldName;	int startIdx;	int endIdx;	int fieldLength;		String userId;		String inType;		String redefine;		String outType;		boolean occurs;		String occursArrayKey;		public boolean isOccurs() {		return occurs;	}	public void setOccurs(boolean occurs) {		this.occurs = occurs;	}	public String getInType() {		return inType;	}	public void setInType(String inType) {		this.inType = inType;	}	public String getOutType() {		return outType;	}	public void setOutType(String outType) {		this.outType = outType;	}	public String getRedefine() {		return redefine;	}	public void setRedefine(String redefine) {		this.redefine = redefine;	}	public String getUserId() {		return userId;	}	public void setUserId(String userId) {		this.userId = userId;	}	public String getfId() {		return fId;	}	public void setfId(String fId) {		this.fId = fId;	}	public String getRecID() {		return recID;	}	public void setRecID(String recID) {		this.recID = recID;	}	public String getRecordType() {		return recordType;	}	public void setRecordType(String recordType) {		this.recordType = recordType;	}	public String getFieldName() {		return fieldName;	}	public void setFieldName(String fieldName) {		this.fieldName = fieldName;	}	public int getStartIdx() {		return startIdx;	}	public void setStartIdx(int startIdx) {		this.startIdx = startIdx;	}	public int getEndIdx() {		return endIdx;	}	public void setEndIdx(int endIdx) {		this.endIdx = endIdx;	}	public int getFieldLength() {		return fieldLength;	}	public void setFieldLength(int fieldLength) {		this.fieldLength = fieldLength;	}	public String getOccursArrayKey() {		return occursArrayKey;	}	public void setOccursArrayKey(String occursArrayKey) {		this.occursArrayKey = occursArrayKey;	}	@Override	public String toString() {		return "InputCFG [fId=" + fId + ", recID=" + recID + ", recordType=" + recordType + ", fieldName=" + fieldName				+ ", startIdx=" + startIdx + ", endIdx=" + endIdx + ", fieldLength=" + fieldLength + ", userId="				+ userId + ", inType=" + inType + ", redefine=" + redefine + ", outType=" + outType + ", occurs="				+ occurs + ", occursArrayKey=" + occursArrayKey + "]";	}}